class HybridBridge(
    private val context: Context,
    private val onOpenCamera: (JSONObject, String) -> Unit,
    private val onGetLocalStorage: (JSONObject, String) -> Unit,
    private val onSetLocalStorage: (JSONObject, String) -> Unit,
    private val onRemoveLocalStorage: (JSONObject, String) -> Unit,
    private val onClearLocalStorage: (JSONObject, String) -> Unit,
    private val onRequestPushPermission: (JSONObject, String) -> Unit,
    private val onShowToast: (JSONObject, String) -> Unit
) {

    @JavascriptInterface
    fun call(method: String, payload: String?) {
        val data = try {
            if (payload.isNullOrBlank()) JSONObject() else JSONObject(payload)
        } catch (_: Exception) {
            JSONObject()
        }
        val callbackId = data.optString("callbackId", "")
        when (method) {
            "openCamera" -> onOpenCamera(data, callbackId)
            "getLocalStorage" -> onGetLocalStorage(data, callbackId)
            "setLocalStorage" -> onSetLocalStorage(data, callbackId)
            "removeLocalStorage" -> onRemoveLocalStorage(data, callbackId)
            "clearLocalStorage" -> onClearLocalStorage(data, callbackId)
            "requestPushPermission" -> onRequestPushPermission(data, callbackId)
            "showToast" -> onShowToast(data, callbackId)
            else -> postResult(callbackId, false, "Unknown method: $method")
        }
    }

    @JavascriptInterface
    fun ping(): String = "pong"

    fun postResult(callbackId: String, success: Boolean, message: String) {
        if (callbackId.isBlank()) return
        val result = JSONObject().apply {
            put("callbackId", callbackId)
            put("success", success)
            put("message", message)
        }
        val js = "window.__hybridNativeBridge && window.__hybridNativeBridge.onResult(${JSONObject.quote(result.toString())});"
        (context as? Activity)?.runOnUiThread {
            val webView = (context.findViewById(android.R.id.content) as? FrameLayout)?.getChildAt(0) as? WebView
            webView?.evaluateJavascript(js, null)
        }
    }
}

